// Collect all 5 PSE HTTP responses and build pseData object
const allInputs = $input.all();

const tickerMap = {
  'AREIT': 'AREIT.PS',
  'CREIT': 'CREIT.PS',
  'MBT':   'MBT.PS',
  'MREIT': 'MREIT.PS',
  'RCR':   'RCR.PS'
};

const fallback = {
  'AREIT.PS': 39.20,
  'CREIT.PS': 3.44,
  'MBT.PS':   64.40,
  'MREIT.PS': 13.80,
  'RCR.PS':   6.80
};

const pseData = {};

for (const input of allInputs) {
  const body = input.json;
  // pselookup returns { symbol, last_trade_price, ... }
  const sym    = body?.symbol || body?.stockSymbol || '';
  const price  = Number(body?.last_trade_price) || Number(body?.price) || Number(body?.close) || 0;
  const psKey  = tickerMap[sym] || tickerMap[sym?.toUpperCase()];

  if (psKey && price > 0) {
    pseData[psKey] = price;
    console.log(`PSE live: ${sym} = ${price}`);
  } else if (psKey) {
    pseData[psKey] = fallback[psKey];
    console.log(`PSE fallback: ${sym} = ${fallback[psKey]} (API returned: ${JSON.stringify(body).slice(0,100)})`);
  }
}

// Fill any missing with fallback
for (const [key, val] of Object.entries(fallback)) {
  if (!pseData[key] || pseData[key] === 0) {
    pseData[key] = val;
    console.log(`PSE fallback fill: ${key} = ${val}`);
  }
}

const source = Object.values(pseData).every((v, i) => v === Object.values(fallback)[i])
  ? 'fallback' : 'live';

console.log('PSE final:', JSON.stringify(pseData), 'source:', source);
return [{ json: { pseData, pse_source: source } }];
